import{c as e,Q as d,j as s,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Extend Claude Code — 功能總覽與選擇指南","description":"","frontmatter":{"title":"Extend Claude Code — 功能總覽與選擇指南","source":"https://code.claude.com/docs/en/features-overview","type":"best-practices"},"headers":[],"relativePath":"research/best-practices/19-features-overview.md","filePath":"research/best-practices/19-features-overview.md","lastUpdated":1779935873000}'),r={name:"research/best-practices/19-features-overview.md"};function a(l,t,n,i,h,c){return d(),s("div",null,[...t[0]||(t[0]=[o('<h1 id="extend-claude-code-—-功能總覽與選擇指南" tabindex="-1">Extend Claude Code — 功能總覽與選擇指南 <a class="header-anchor" href="#extend-claude-code-—-功能總覽與選擇指南" aria-label="Permalink to &quot;Extend Claude Code — 功能總覽與選擇指南&quot;">​</a></h1><blockquote><p>來源：<a href="https://code.claude.com/docs/en/features-overview" target="_blank" rel="noreferrer">https://code.claude.com/docs/en/features-overview</a> 收錄日期：2026-05-01 涵蓋：CLAUDE.md vs Skills vs MCP vs Subagents vs Agent Teams vs Hooks vs Plugins 完整比較</p></blockquote><hr><h2 id="功能全覽" tabindex="-1">功能全覽 <a class="header-anchor" href="#功能全覽" aria-label="Permalink to &quot;功能全覽&quot;">​</a></h2><p>Extensions 插入 agentic loop 的不同位置：</p><table tabindex="0"><thead><tr><th>功能</th><th>作用</th><th>載入時機</th></tr></thead><tbody><tr><td><strong>CLAUDE.md</strong></td><td>每次 session 自動載入的持久 context</td><td>Session 開始</td></tr><tr><td><strong>Skills</strong></td><td>可重用的知識和可呼叫的 workflows</td><td>按需（描述在 session start 載入，內容在使用時載入）</td></tr><tr><td><strong>MCP</strong></td><td>連接外部服務和工具</td><td>Session 開始（tool names）；schema 按需</td></tr><tr><td><strong>Subagents</strong></td><td>在隔離 context 中執行，回傳摘要</td><td>被 spawn 時</td></tr><tr><td><strong>Agent teams</strong></td><td>協調多個獨立 session，共享 tasks 和點對點通訊</td><td>各 session 獨立</td></tr><tr><td><strong>Hooks</strong></td><td>在 lifecycle events 執行腳本、HTTP 請求、prompt、或 subagent</td><td>觸發事件時</td></tr><tr><td><strong>Plugins/Marketplaces</strong></td><td>打包分發上述功能的單元</td><td>安裝後按各功能規則</td></tr></tbody></table><p>Skills 是最靈活的 extension。可用 <code>/deploy</code> 呼叫，也可讓 Claude 在相關情境自動載入。可在當前對話或隔離 context（via subagents）中執行。</p><hr><h2 id="何時加入各功能-觸發點判斷表" tabindex="-1">何時加入各功能（觸發點判斷表） <a class="header-anchor" href="#何時加入各功能-觸發點判斷表" aria-label="Permalink to &quot;何時加入各功能（觸發點判斷表）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>觸發情況</th><th>加入什麼</th></tr></thead><tbody><tr><td>Claude 同一慣例或指令犯兩次錯</td><td>加入 <a href="/cc-workspace-docs/en/memory">CLAUDE.md</a></td></tr><tr><td>你一直輸入同樣的 prompt 開始某個任務</td><td>存成可呼叫的 <a href="/cc-workspace-docs/en/skills">skill</a></td></tr><tr><td>你第三次把同樣的 playbook 或多步流程貼進對話</td><td>捕捉為 <a href="/cc-workspace-docs/en/skills">skill</a></td></tr><tr><td>你一直要複製 Claude 看不到的 tab 資料</td><td>把該系統連接為 <a href="/cc-workspace-docs/en/mcp">MCP server</a></td></tr><tr><td>某個側邊任務把你的對話淹沒在你不會再看的輸出</td><td>用 <a href="/cc-workspace-docs/en/sub-agents">subagent</a> 路由</td></tr><tr><td>你希望某件事每次都自動發生，不需要詢問</td><td>寫 <a href="/cc-workspace-docs/en/hooks-guide">hook</a></td></tr><tr><td>第二個 repo 需要相同的設定</td><td>打包成 <a href="/cc-workspace-docs/en/plugins">plugin</a></td></tr></tbody></table><p>同樣的觸發點告訴你何時更新已有的功能。重複的錯誤或 code review 評論 = CLAUDE.md 的更新（不是臨時修正）。你一直手動調整的 workflow = 需要再次修改的 skill。</p><hr><h2 id="功能比較詳解" tabindex="-1">功能比較詳解 <a class="header-anchor" href="#功能比較詳解" aria-label="Permalink to &quot;功能比較詳解&quot;">​</a></h2><h3 id="claude-md-vs-skill" tabindex="-1">CLAUDE.md vs Skill <a class="header-anchor" href="#claude-md-vs-skill" aria-label="Permalink to &quot;CLAUDE.md vs Skill&quot;">​</a></h3><table tabindex="0"><thead><tr><th>面向</th><th>CLAUDE.md</th><th>Skill</th></tr></thead><tbody><tr><td><strong>載入時機</strong></td><td>每次 session 自動</td><td>按需</td></tr><tr><td><strong>可引入檔案</strong></td><td>是，用 <code>@path</code></td><td>是，用 <code>@path</code></td></tr><tr><td><strong>可觸發 workflows</strong></td><td>否</td><td>是，用 <code>/&lt;name&gt;</code></td></tr><tr><td><strong>最適合</strong></td><td>&quot;Always do X&quot; 規則</td><td>參考資料、可呼叫 workflows</td></tr></tbody></table><p><strong>經驗法則</strong>：CLAUDE.md 控制在 200 行以內。成長太快時，把參考資料移到 skills 或拆進 <code>.claude/rules/</code> 檔案。</p><h3 id="skill-vs-subagent" tabindex="-1">Skill vs Subagent <a class="header-anchor" href="#skill-vs-subagent" aria-label="Permalink to &quot;Skill vs Subagent&quot;">​</a></h3><table tabindex="0"><thead><tr><th>面向</th><th>Skill</th><th>Subagent</th></tr></thead><tbody><tr><td><strong>本質</strong></td><td>可重用的指令、知識、workflows</td><td>有自己 context 的隔離 worker</td></tr><tr><td><strong>核心優勢</strong></td><td>跨 contexts 分享內容</td><td>Context 隔離；工作在獨立空間完成，只有摘要回傳</td></tr><tr><td><strong>最適合</strong></td><td>參考資料、可呼叫 workflows</td><td>讀取大量檔案、平行工作、專門 workers</td></tr></tbody></table><p><strong>兩者可結合</strong>：subagent 可以預載特定 skills（<code>skills:</code> 欄位）；skill 可以用 <code>context: fork</code> 在隔離 context 中執行。</p><h3 id="claude-md-vs-rules-vs-skills-三層區分" tabindex="-1">CLAUDE.md vs Rules vs Skills（三層區分） <a class="header-anchor" href="#claude-md-vs-rules-vs-skills-三層區分" aria-label="Permalink to &quot;CLAUDE.md vs Rules vs Skills（三層區分）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>面向</th><th>CLAUDE.md</th><th><code>.claude/rules/</code></th><th>Skill</th></tr></thead><tbody><tr><td><strong>載入時機</strong></td><td>每次 session</td><td>每次 session，或開啟符合路徑的檔案時</td><td>按需</td></tr><tr><td><strong>範圍</strong></td><td>整個專案</td><td>可限縮到特定路徑</td><td>任務特定</td></tr><tr><td><strong>最適合</strong></td><td>核心慣例和 build 指令</td><td>語言或目錄特定的指南</td><td>參考資料、重複 workflows</td></tr></tbody></table><h3 id="subagent-vs-agent-team" tabindex="-1">Subagent vs Agent Team <a class="header-anchor" href="#subagent-vs-agent-team" aria-label="Permalink to &quot;Subagent vs Agent Team&quot;">​</a></h3><table tabindex="0"><thead><tr><th>面向</th><th>Subagent</th><th>Agent Team</th></tr></thead><tbody><tr><td><strong>Context</strong></td><td>自己的 context window；結果回傳給呼叫者</td><td>自己的 context window；完全獨立</td></tr><tr><td><strong>通訊</strong></td><td>只向主 agent 回報結果</td><td>成員之間直接互傳訊息</td></tr><tr><td><strong>協調</strong></td><td>主 agent 管理所有工作</td><td>共享 task list，自我協調</td></tr><tr><td><strong>最適合</strong></td><td>只需要結果的聚焦任務</td><td>需要討論和協作的複雜工作</td></tr><tr><td><strong>Token 成本</strong></td><td>較低（結果摘要回主 context）</td><td>較高（每個成員都是獨立 Claude instance）</td></tr></tbody></table><p><strong>轉換時機</strong>：如果你在跑平行 subagents 但遭遇 context limits，或 subagents 需要互相通訊 → Agent teams 是自然的下一步。</p><blockquote><p>Agent teams 為實驗性功能，預設關閉。</p></blockquote><h3 id="mcp-vs-skill" tabindex="-1">MCP vs Skill <a class="header-anchor" href="#mcp-vs-skill" aria-label="Permalink to &quot;MCP vs Skill&quot;">​</a></h3><table tabindex="0"><thead><tr><th>面向</th><th>MCP</th><th>Skill</th></tr></thead><tbody><tr><td><strong>本質</strong></td><td>連接外部服務的協定</td><td>知識、workflows、參考資料</td></tr><tr><td><strong>提供</strong></td><td>Tools 和資料存取</td><td>知識、workflows、參考資料</td></tr><tr><td><strong>範例</strong></td><td>Slack 整合、資料庫查詢、瀏覽器控制</td><td>Code review checklist、deploy workflow、API style guide</td></tr></tbody></table><p><strong>搭配使用</strong>：MCP 提供能力，Skill 提供如何有效使用的知識。例：MCP server 連接資料庫，Skill 教 Claude 你的資料模型和常用 query patterns。</p><h3 id="hook-vs-skill" tabindex="-1">Hook vs Skill <a class="header-anchor" href="#hook-vs-skill" aria-label="Permalink to &quot;Hook vs Skill&quot;">​</a></h3><table tabindex="0"><thead><tr><th>面向</th><th>Hook</th><th>Skill</th></tr></thead><tbody><tr><td><strong>執行內容</strong></td><td>shell 指令、HTTP 請求、LLM prompt、或 subagent</td><td>Claude 讀取並遵循的指令</td></tr><tr><td><strong>觸發</strong></td><td>Lifecycle events（如 PostToolUse、SessionStart）</td><td>你輸入 <code>/&lt;name&gt;</code>，或 Claude 判斷與你的任務相關</td></tr><tr><td><strong>確定性</strong></td><td>事件觸發時一定執行</td><td>Claude 詮釋指令；結果可能有差異</td></tr><tr><td><strong>Context 成本</strong></td><td>零（除非 hook 回傳輸出）</td><td>描述每次 session 載入；內容在使用時載入</td></tr><tr><td><strong>最適合</strong></td><td>Lint 後編輯、封鎖不安全指令、logging、通知</td><td>需要推理的 workflows、參考資料、多步驟任務</td></tr></tbody></table><p><strong>重要</strong>：CLAUDE.md 或 Skill 中的「絕不編輯 <code>.env</code>」是請求，不是保證。<code>PreToolUse</code> hook 封鎖編輯才是強制執行。<strong>如果規則必須每次都成立，做成 hook 而非 prompt 指令。</strong></p><p><strong>Hook 輸出進入 context</strong>：<code>PostToolUse</code> hook 跑 linter → 結果以文字回傳給 Claude 讀取；<code>/fix-lint</code> skill 告訴 Claude 如何解決。</p><hr><h2 id="功能分層-多層級設定" tabindex="-1">功能分層（多層級設定） <a class="header-anchor" href="#功能分層-多層級設定" aria-label="Permalink to &quot;功能分層（多層級設定）&quot;">​</a></h2><p>功能可在多個層級定義：user-wide、per-project、via plugins、managed policies。</p><ul><li><strong>CLAUDE.md files</strong>：累加性，所有層級的內容同時進入 context</li><li><strong>Skills 和 Subagents</strong>：名稱覆蓋（managed &gt; user &gt; project for skills）；Plugin skills 用命名空間避免衝突</li><li><strong>MCP servers</strong>：local &gt; project &gt; user</li><li><strong>Hooks</strong>：合併，所有 hooks 都會在對應事件觸發</li></ul><hr><h2 id="功能組合-patterns" tabindex="-1">功能組合 Patterns <a class="header-anchor" href="#功能組合-patterns" aria-label="Permalink to &quot;功能組合 Patterns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pattern</th><th>如何運作</th><th>範例</th></tr></thead><tbody><tr><td><strong>Skill + MCP</strong></td><td>MCP 提供連接；Skill 教 Claude 如何有效使用</td><td>MCP 連資料庫，Skill 記錄 schema 和 query patterns</td></tr><tr><td><strong>Skill + Subagent</strong></td><td>Skill 派出 subagents 平行工作</td><td><code>/audit</code> skill 啟動 security、performance、style 三個 subagents</td></tr><tr><td><strong>CLAUDE.md + Skills</strong></td><td>CLAUDE.md 放常駐規則；Skills 放按需參考資料</td><td>CLAUDE.md 說「遵循我們的 API 慣例」，Skill 包含完整 API style guide</td></tr><tr><td><strong>Hook + MCP</strong></td><td>Hook 透過 MCP 觸發外部操作</td><td>編輯後 hook 透過 Slack MCP 發送通知</td></tr></tbody></table><hr><h2 id="context-成本對照表" tabindex="-1">Context 成本對照表 <a class="header-anchor" href="#context-成本對照表" aria-label="Permalink to &quot;Context 成本對照表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>載入時機</th><th>載入什麼</th><th>Context 成本</th></tr></thead><tbody><tr><td><strong>CLAUDE.md</strong></td><td>Session start</td><td>完整內容</td><td>每個 request</td></tr><tr><td><strong>Skills</strong></td><td>Session start + 使用時</td><td>描述在 start，完整內容在使用時</td><td>低（描述每個 request）*</td></tr><tr><td><strong>MCP servers</strong></td><td>Session start</td><td>Tool names；完整 schema 按需</td><td>低（直到 tool 被使用）</td></tr><tr><td><strong>Subagents</strong></td><td>被 spawn 時</td><td>獨立的新 context + 指定的 skills</td><td>與主 session 隔離</td></tr><tr><td><strong>Hooks</strong></td><td>觸發時</td><td>不載入任何東西（外部執行）</td><td>零（除非 hook 回傳輸出）</td></tr></tbody></table><p>*設定 <code>disable-model-invocation: true</code> 可讓 skill 完全對 Claude 隱藏，直到你手動呼叫 → context 成本歸零。</p><h3 id="各功能載入時序" tabindex="-1">各功能載入時序 <a class="header-anchor" href="#各功能載入時序" aria-label="Permalink to &quot;各功能載入時序&quot;">​</a></h3><ol><li><strong>Session start</strong>：CLAUDE.md 全部內容 + MCP tool names + Skill 描述</li><li><strong>Skill 被呼叫/相關時</strong>：Skill 完整內容載入</li><li><strong>MCP tool 被使用時</strong>：該 tool 的完整 schema 載入</li><li><strong>Subagent spawn 時</strong>：隔離的新 context（包含：system prompt、指定 skills 完整內容、CLAUDE.md、git status）</li></ol><hr><hr><h2 id="內建-cli-工具指令-w14–w17-新增" tabindex="-1">內建 CLI 工具指令（W14–W17 新增） <a class="header-anchor" href="#內建-cli-工具指令-w14–w17-新增" aria-label="Permalink to &quot;內建 CLI 工具指令（W14–W17 新增）&quot;">​</a></h2><h3 id="powerup-w14" tabindex="-1"><code>/powerup</code>（W14） <a class="header-anchor" href="#powerup-w14" aria-label="Permalink to &quot;`/powerup`（W14）&quot;">​</a></h3><p>內建動畫 demo 的互動式功能教學課程，直接在 terminal 中學習 Claude Code 各項功能：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /powerup</span></span></code></pre></div><h3 id="usage-breakdown-w16–w17" tabindex="-1"><code>/usage</code> Breakdown（W16–W17） <a class="header-anchor" href="#usage-breakdown-w16–w17" aria-label="Permalink to &quot;`/usage` Breakdown（W16–W17）&quot;">​</a></h3><p>顯示用量驅動因素分析：parallel sessions、subagents、cache misses、long context，各附百分比 + 優化提示。<code>d</code>/<code>w</code> 切換 day / week 視圖：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /usage    # d = day view, w = week view</span></span></code></pre></div><p>W17 更新：<code>/cost</code> 和 <code>/stats</code> 合併入 <code>/usage</code>，舊名稱仍可用（自動跳到對應 tab）。</p><hr><h2 id="相關文件" tabindex="-1">相關文件 <a class="header-anchor" href="#相關文件" aria-label="Permalink to &quot;相關文件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>文件</th></tr></thead><tbody><tr><td>CLAUDE.md</td><td>/en/memory</td></tr><tr><td>Skills</td><td>/en/skills</td></tr><tr><td>Subagents</td><td>/en/sub-agents</td></tr><tr><td>Agent teams</td><td>/en/agent-teams</td></tr><tr><td>MCP</td><td>/en/mcp</td></tr><tr><td>Hooks</td><td>/en/hooks-guide</td></tr><tr><td>Plugins</td><td>/en/plugins</td></tr><tr><td>Plugin Marketplaces</td><td>/en/plugin-marketplaces</td></tr></tbody></table>',58)])])}const k=e(r,[["render",a]]);export{u as __pageData,k as default};
